#!/bin/bash\n# Create a production-ready Helm chart for a Next.js application\n\nAPP_NAME=\"$1\"\n\nif [ -z \"$APP_NAME\" ]; then\n    echo \"Usage: $0 <app-name>\"\n    echo \"Example: $0 learnflow-frontend\"\n    exit 1\n}\n\nHELM_CHART_DIR=\"./helm-charts/$APP_NAME\"\n\n# Ensure application name is provided\nif [ -z \"$APP_NAME\" ]; then\n    echo \"❌ Error: Application name not provided.\"\n    exit 1\n}\n\n# Check if image info is available (from build_image.sh)\nif [ -f \"../.nextjs-image-info\" ]; then\n    source ../.nextjs-image-info\nelse\n    echo \"⚠️ Warning: Image information not found. Using default registry and tag.\"\n    IMAGE_REGISTRY=\"your-docker-registry.io\"\n    IMAGE_TAG=\"latest\"\n}\n\n# Create Helm chart boilerplate\necho \"Creating Helm chart for \'$APP_NAME\' in $HELM_CHART_DIR...\"\nhelm create \"$HELM_CHART_DIR\" --starter=./nextjs-starter # Using a conceptual starter\nif [ $? -ne 0 ]; then\n    echo \"❌ Failed to create Helm chart boilerplate.\"\n    # Attempt to create manually if helm create fails for starter\n    mkdir -p \"$HELM_CHART_DIR/templates\"\n    mkdir -p \"$HELM_CHART_DIR/charts\"\n    touch \"$HELM_CHART_DIR/values.yaml\"\n    touch \"$HELM_CHART_DIR/Chart.yaml\"\n    touch \"$HELM_CHART_DIR/templates/_helpers.tpl\"\n    touch \"$HELM_CHART_DIR/templates/deployment.yaml\"\n    touch \"$HELM_CHART_DIR/templates/service.yaml\"\n    echo \"Created basic Helm chart structure manually.\"\n}\n\n# Update Chart.yaml\ncat > \"$HELM_CHART_DIR/Chart.yaml\" << EOF\napiVersion: v2\nname: $APP_NAME\ndescription: A Helm chart for deploying the $APP_NAME Next.js application to Kubernetes\ntype: application\nversion: 0.1.0\nappVersion: \"1.0.0\"\nEOF\n\n# Update values.yaml for enterprise readiness\ncat > \"$HELM_CHART_DIR/values.yaml\" << EOF\nreplicaCount: 2 # Enterprise HA\n\nimage:\n  repository: ${IMAGE_REGISTRY}/${APP_NAME}\n  pullPolicy: IfNotPresent\n  # Overrides the image tag whose default is the chart appVersion.\n  tag: \"${IMAGE_TAG}\"\n\nimagePullSecrets: []\nnameOverride: \"\"\nfullnameOverride: \"\"\n\nserviceAccount:\n  # Specifies whether a service account should be created\n  create: true\n  # Annotations to add to the service account\n  annotations: {}\n  # The name of the service account to use. If not set and create is true, a name is generated using the fullname template\n  name: \"\"\n\npodAnnotations: {}\npodSecurityContext: {}\n  # fsGroup: 2000\n\nsecurityContext:\n  # capabilities:\n  #   drop:\n  #   - ALL\n  # readOnlyRootFilesystem: true\n  # runAsNonRoot: true\n  # runAsUser: 1000\n\nservice:\n  type: ClusterIP\n  port: 3000\n\ningress:\n  enabled: true\n  className: \"nginx\"\n  annotations: {}\n    # kubernetes.io/ingress.class: nginx\n    # kubernetes.io/tls-acme: \"true\"\n  hosts:\n    - host: ${APP_NAME}.your-enterprise.com # Replace with actual enterprise domain\n      paths:\n        - path: /\n          pathType: ImplementationSpecific\n  tls: []\n  #  - secretName: chart-example-tls\n  #    hosts:\n  #      - chart-example.local\n\nresources: {}\n  # We usually recommend not to specify default resources and to leave this as a conscious\n  # choice for the user. This also increases chances charts run on environments with little\n  # resources, such as Minikube.\n  # limits:\n  #   cpu: 100m\n  #   memory: 128Mi\n  # requests:\n  #   cpu: 100m\n  #   memory: 128Mi\n\nautoscaling:\n  enabled: true # Enterprise HPA\n  minReplicas: 2\n  maxReplicas: 10\n  targetCPUUtilizationPercentage: 80\n  # targetMemoryUtilizationPercentage: 80\n\nnodeSelector: {}\n\ntolerations: []\n\naffinity: {}\nEOF\n\n# Create enterprise deployment.yaml template\ncat > \"$HELM_CHART_DIR/templates/deployment.yaml\" << EOF\napiVersion: apps/v1\nkind: Deployment\nmetadata:\n  name: {{ include \"${APP_NAME}.fullname\" . }}\n  labels:\n    {{- include \"${APP_NAME}.labels\" . | nindent 4 }}\nspec:\n  {{- if not .Values.autoscaling.enabled }}\n  replicas: {{ .Values.replicaCount }}\n  {{- end }}\n  selector:\n    matchLabels:\n      {{- include \"${APP_NAME}.selectorLabels\" . | nindent 6 }}\n  template:\n    metadata:\n      {{- with .Values.podAnnotations }}\n      annotations:\n        {{- toYaml . | nindent 8 }}\n      {{- end }}\n      labels:\n        {{- include \"${APP_NAME}.selectorLabels\" . | nindent 8 }}\n    spec:\n      {{- with .Values.imagePullSecrets }}\n      imagePullSecrets:\n        {{- toYaml . | nindent 8 }}\n      {{- end }}\n      serviceAccountName: {{ include \"${APP_NAME}.serviceAccountName\" . }}\n      securityContext:\n        {{- toYaml .Values.podSecurityContext | nindent 8 }}\n      containers:\n        - name: {{ .Chart.Name }}\n          securityContext:\n            {{- toYaml .Values.securityContext | nindent 12 }}\n          image: \"{{ .Values.image.repository }}:{{ .Values.image.tag | default .Chart.AppVersion }}\"\n          imagePullPolicy: {{ .Values.image.pullPolicy }}\n          ports:\n            - name: http\n              containerPort: 3000\n              protocol: TCP\n          livenessProbe:\n            httpGet:\n              path: /api/health\n              port: http\n            initialDelaySeconds: 10\n            periodSeconds: 10\n          readinessProbe:\n            httpGet:\n              path: /api/health\n              port: http\n            initialDelaySeconds: 5\n            periodSeconds: 5\n          resources:\n            {{- toYaml .Values.resources | nindent 12 }}\n          env:\n            - name: NODE_ENV\n              value: production\n            - name: NEXT_PUBLIC_APP_NAME\n              value: {{ .Chart.Name | quote }}\n            # Add any other enterprise environment variables here, potentially from secrets\n      {{- with .Values.nodeSelector }}\n      nodeSelector:\n        {{- toYaml . | nindent 8 }}\n      {{- end }}\n      {{- with .Values.affinity }}\n      affinity:\n        {{- toYaml . | nindent 8 }}\n      {{- end }}\n      {{- with .Values.tolerations }}\n      tolerations:\n        {{- toYaml . | nindent 8 }}\n      {{- end }}\nEOF\n\n# Create enterprise service.yaml template\ncat > \"$HELM_CHART_DIR/templates/service.yaml\" << EOF\napiVersion: v1\nkind: Service\nmetadata:\n  name: {{ include \"${APP_NAME}.fullname\" . }}\n  labels:\n    {{- include \"${APP_NAME}.labels\" . | nindent 4 }}\nspec:\n  type: {{ .Values.service.type }}\n  ports:\n    - port: {{ .Values.service.port }}\n      targetPort: http\n      protocol: TCP\n      name: http\n  selector:\n    {{- include \"${APP_NAME}.selectorLabels\" . | nindent 4 }}\nEOF\n\n# Create enterprise ingress.yaml template\ncat > \"$HELM_CHART_DIR/templates/ingress.yaml\" << EOF\n{{- if .Values.ingress.enabled -}}\napiVersion: networking.k8s.io/v1\nkind: Ingress\nmetadata:\n  name: {{ include \"${APP_NAME}.fullname\" . }}\n  labels:\n    {{- include \"${APP_NAME}.labels\" . | nindent 4 }}\n  {{- with .Values.ingress.annotations }}\n  annotations:\n    {{- toYaml . | nindent 4 }}\n  {{- end }}\nspec:\n  {{- if .Values.ingress.className }}\n  ingressClassName: {{ .Values.ingress.className }}\n  {{- end }}\n  rules:\n    {{- range .Values.ingress.hosts }}\n    - host: {{ .host | quote }}\n      http:\n        paths:\n          {{- range .paths }}\n          - path: {{ .path }}\n            pathType: {{ .pathType }}\n            backend:\n              service:\n                name: {{ include \"${APP_NAME}.fullname\" $ }}\n                port:\n                  name: http\n          {{- end }}\n    {{- end }}\n  {{- if .Values.ingress.tls }}\n  tls:\n    {{- toYaml .Values.ingress.tls | nindent 4 }}\n  {{- end }}\nEOF\n\n# Create enterprise HPA.yaml template\ncat > \"$HELM_CHART_DIR/templates/hpa.yaml\" << EOF\n{{- if .Values.autoscaling.enabled }}\napiVersion: autoscaling/v2\nkind: HorizontalPodAutoscaler\nmetadata:\n  name: {{ include \"${APP_NAME}.fullname\" . }}\n  labels:\n    {{- include \"${APP_NAME}.labels\" . | nindent 4 }}\nspec:\n  scaleTargetRef:\n    apiVersion: apps/v1\n    kind: Deployment\n    name: {{ include \"${APP_NAME}.fullname\" . }}\n  minReplicas: {{ .Values.autoscaling.minReplicas }}\n  maxReplicas: {{ .Values.autoscaling.maxReplicas }}\n  metrics:\n    {{- if .Values.autoscaling.targetCPUUtilizationPercentage }}\n    - type: Resource\n      resource:\n        name: cpu\n        target:\n          type: Utilization\n          averageUtilization: {{ .Values.autoscaling.targetCPUUtilizationPercentage }}\n    {{- end }}\n    {{- if .Values.autoscaling.targetMemoryUtilizationPercentage }}\n    - type: Resource\n      resource:\n        name: memory\n        target:\n          type: Utilization\n          averageUtilization: {{ .Values.autoscaling.targetMemoryUtilizationPercentage }}\n    {{- end }}\nEOF\n\n# Create enterprise _helpers.tpl for common labels and names\ncat > \"$HELM_CHART_DIR/templates/_helpers.tpl\" << EOF\n{{/*\nExpand the name of the chart.\n*/}}\n{{- define \"${APP_NAME}.name\" -}}\n{{- default .Chart.Name .Values.nameOverride -}}\n{{- end -}}\n\n{{/*\nCreate a default fully qualified app name.\nWe truncate at 63 chars because some Kubernetes name fields are limited to this (by the DNS naming spec).\nIf release name contains chart name it will be used as a full name.\n*/}}\n{{- define \"${APP_NAME}.fullname\" -}}\n{{- if .Values.fullnameOverride -}}\n{{- .Values.fullnameOverride | trunc 63 | trimSuffix \"-\" -}}\n{{- else -}}\n{{- \$name := default .Chart.Name .Values.nameOverride -}}\n{{- if contains \$name .Release.Name -}}\n{{- .Release.Name | trunc 63 | trimSuffix \"-\" -}}\n{{- else -}}\n{{- printf \"%s-%s\" .Release.Name \$name | trunc 63 | trimSuffix \"-\" -}}\n{{- end -}}\n{{- end -}}\n{{- end -}}\n\n{{/*\nCreate chart name and version as a default label.\n*/}}\n{{- define \"${APP_NAME}.labels\" -}}\nhapp.kubernetes.io/name: {{ include \"${APP_NAME}.name\" . }}\nhelm.sh/chart: {{ include \"${APP_NAME}.chart\" . }}\napp.kubernetes.io/instance: {{ .Release.Name }}\n{{- if .Chart.AppVersion }}\napp.kubernetes.io/version: {{ .Chart.AppVersion | quote }}\n{{- end -}}\napp.kubernetes.io/managed-by: {{ .Release.Service }}\n{{- end -}}\n\n{{/*\nSelector labels\n*/}}\n{{- define \"${APP_NAME}.selectorLabels\" -}}\napp.kubernetes.io/name: {{ include \"${APP_NAME}.name\" . }}\napp.kubernetes.io/instance: {{ .Release.Name }}\n{{- end -}}\n\n{{/*\nCreate the name of the service account to use\n*/}}\n{{- define \"${APP_NAME}.serviceAccountName\" -}}\n{{- if .Values.serviceAccount.create -}}\n    {{- default (include \"${APP_NAME}.fullname\" .) .Values.serviceAccount.name -}}\n{{- else -}}\n    {{- default \"default\" .Values.serviceAccount.name -}}\n{{- end -}}\n{{- end -}}\n\n{{/*\nReturn the appropriate apiVersion for Ingress\n*/}}\n{{- define \"ingress.apiVersion\" -}}\n{{- if semverCompare \">=1.19-0\" .Capabilities.KubeVersion.GitVersion -}}\n    {{- print \"networking.k8s.io/v1\" -}}\n{{- else if semverCompare \">=1.14-0\" .Capabilities.KubeVersion.GitVersion -}}\n    {{- print \"extensions/v1beta1\" -}}\n{{- else -}}\n    {{- print \"extensions/v1beta1\" -}}\n{{- end -}}\n{{- end -}}\nEOF\n\n# Only this output enters agent context:\necho \"✓ Helm chart for Next.js application \'$APP_NAME\' created with enterprise configurations.\"\n